parameters.jsCode:
const response = $('HTTP_PhoneLookup').first().json;
const appointments = response.appointments;
const CallerID = $('When Executed by Another Workflow').first().json.CallerID;
const Instance = $('When Executed by Another Workflow').first().json.Instance;

const ahora = new Date();
const citasFuturas = appointments.filter(appt => {
  const [y, m, d] = appt.date.split('-').map(Number);
  const [hh, mm] = appt.time.split(':').map(Number);
  const appointmentDate = new Date(y, m - 1, d, hh, mm);
  return appointmentDate > ahora;
});

if (citasFuturas.length === 0) {
  return [{
    json: {
      tiene_citas: false,
      mensaje: '❌ No tenés citas futuras registradas para reagendar.',
      numero: CallerID,
      instancia: Instance,
      citas: []
    }
  }];
}

if (citasFuturas.length === 1) {
  const cita = citasFuturas[0];
  const [year, month, day] = cita.date.split('-');
  const fechaTexto = `${day}/${month}/${year}`;

  const mensaje =
    `📅 Tenés una cita programada:\n\n` +
    `👨‍⚕️ Doctor: ${cita.doctor_name}\n` +
    `📆 Fecha: ${fechaTexto}\n` +
    `⏰ Hora: ${cita.time}\n\n` +
    `¿Deseás *reagendar* esta cita?\nRespondé *SI* para continuar o *NO* para mantenerla.`;

  return [{
    json: {
      tiene_citas: true,
      unica_cita: true,
      cita_id: cita.id,
      doctor_id: cita.doctor_id,
      doctor_name: cita.doctor_name,
      patient_name: cita.patient_name,
      mensaje,
      numero: CallerID,
      instancia: Instance,
      citas: citasFuturas
    }
  }];
}

let menu = `📅 Tenés las siguientes citas programadas:\n\n`;
const emojis = ['1️⃣','2️⃣','3️⃣','4️⃣','5️⃣','6️⃣','7️⃣','8️⃣','9️⃣','🔟'];
citasFuturas.forEach((cita, index) => {
  const [year, month, day] = cita.date.split('-');
  const emoji = emojis[index] || `${index + 1}.`;
  menu += `${emoji} ${day}/${month}/${year} - ${cita.time} (${cita.doctor_name})\n`;
});
menu += `\nPor favor, respondé con el *número* de la cita que deseás reagendar.`;

return [{
  json: {
    tiene_citas: true,
    unica_cita: false,
    mensaje: menu,
    numero: CallerID,
    instancia: Instance,
    citas: citasFuturas
  }
}];

const rows = $('PG_SearchByName').all().map(item => item.json);
const CallerID = $('When Executed by Another Workflow').first().json.CallerID;
const Instance = $('When Executed by Another Workflow').first().json.Instance;

if (rows.length === 1) {
  const cita = rows[0];
  const [year, month, day] = cita.date.split('-');
  const fechaTexto = `${day}/${month}/${year}`;

  const mensaje =
    `📅 Encontré una cita programada:\n\n` +
    `👨‍⚕️ Doctor: ${cita.doctor_name}\n` +
    `📆 Fecha: ${fechaTexto}\n` +
    `⏰ Hora: ${cita.time}\n\n` +
    `¿Deseás *reagendar* esta cita?\nRespondé *SI* para continuar o *NO* para mantenerla.`;

  return [{
    json: {
      unica_cita: true,
      cita_id: cita.id,
      doctor_id: cita.doctor_id,
      doctor_name: cita.doctor_name,
      patient_name: cita.patient_name,
      mensaje,
      numero: CallerID,
      instancia: Instance,
      citas: rows
    }
  }];
}

let menu = `📅 Encontré las siguientes citas:\n\n`;
const emojis = ['1️⃣','2️⃣','3️⃣','4️⃣','5️⃣','6️⃣','7️⃣','8️⃣','9️⃣','🔟'];
rows.forEach((cita, index) => {
  const [year, month, day] = cita.date.split('-');
  const emoji = emojis[index] || `${index + 1}.`;
  menu += `${emoji} ${day}/${month}/${year} - ${cita.time} (${cita.doctor_name})\n`;
});
menu += `\nPor favor, respondé con el *número* de la cita que deseás reagendar.`;

return [{
  json: {
    unica_cita: false,
    mensaje: menu,
    numero: CallerID,
    instancia: Instance,
    citas: rows
  }
}];

const input = $('When Executed by Another Workflow').first().json.Message;
const CallerID = $('When Executed by Another Workflow').first().json.CallerID;
const Instance = $('When Executed by Another Workflow').first().json.Instance;
const citasRaw = $('Get_HorariosDisponibles').first().json.HorariosDisponibles;

let citas;
if (typeof citasRaw === 'string') {
  citas = JSON.parse(citasRaw);
} else {
  citas = citasRaw;
}

const opcion = parseInt(input, 10);

if (isNaN(opcion) || opcion < 1 || opcion > citas.length) {
  return [{ json: { valido: false, mensaje: '❌ Opción inválida. Respondé con el número de la cita.', numero: CallerID, instancia: Instance } }];
}

const citaSeleccionada = citas[opcion - 1];
const [year, month, day] = citaSeleccionada.date.split('-');
const fechaTexto = `${day}/${month}/${year}`;

const mensaje =
  `📆 Fecha: ${fechaTexto}\n` +
  `⏰ Hora: ${citaSeleccionada.time}\n` +
  `👨‍⚕️ Doctor: ${citaSeleccionada.doctor_name}\n\n` +
  `¿Deseás *reagendar* esta cita?\nRespondé *SI* para continuar o *NO* para mantenerla.`;

return [{
  json: {
    valido: true,
    cita_id: citaSeleccionada.id,
    doctor_id: citaSeleccionada.doctor_id,
    doctor_name: citaSeleccionada.doctor_name,
    patient_name: citaSeleccionada.patient_name,
    mensaje,
    numero: CallerID,
    instancia: Instance
  }
}];

const texto = $('When Executed by Another Workflow').first().json.Message;

const regex = /^(0[1-9]|[12][0-9]|3[01])\/(0[1-9]|1[0-2])\/\d{4}$/;

if (!regex.test(texto)) {
  return [{ json: { valido: false, motivo: 'Formato inválido (dd/MM/yyyy)' } }];
}

const [dia, mes, anio] = texto.split('/').map(Number);
const fecha = new Date(anio, mes - 1, dia);

const fechaValida =
  fecha.getFullYear() === anio &&
  fecha.getMonth() === mes - 1 &&
  fecha.getDate() === dia;

if (!fechaValida) {
  return [{ json: { valido: false, motivo: 'La fecha no existe' } }];
}

return [{
  json: {
    valido: true,
    fecha_original: texto,
    fecha_date: fecha.toISOString()
  }
}];

const response = $('HTTP_AvailableTimes').first().json;
const doctorName = $('Get_DoctorName').first().json.doctorName;
const fechaISO = $('Code in JavaScript1').first().json.fecha_date;
const CallerID = $('When Executed by Another Workflow').first().json.CallerID;
const Instance = $('When Executed by Another Workflow').first().json.Instance;

const fecha = new Date(fechaISO);
const dia = String(fecha.getDate()).padStart(2, '0');
const mes = String(fecha.getMonth() + 1).padStart(2, '0');
const anio = fecha.getFullYear();
const fechaTexto = `${dia}/${mes}/${anio}`;

if (!response.success || !response.times || response.times.length === 0) {
  return [{
    json: {
      hayDisponibilidad: false,
      mensaje: `❌ No hay horarios disponibles para ${doctorName} el ${fechaTexto}.\n\nPor favor, elegí otra fecha escribiendo en formato DD/MM/AAAA.`,
      numero: CallerID,
      instancia: Instance,
      horariosDisponibles: []
    }
  }];
}

const disponibles = response.times;
const emojis = ['1️⃣','2️⃣','3️⃣','4️⃣','5️⃣','6️⃣','7️⃣','8️⃣','9️⃣','🔟'];

let mensaje = `Estos son los horarios disponibles para ${doctorName} el ${fechaTexto}:\n\n`;
disponibles.forEach((h, i) => {
  const emoji = emojis[i] || `${i+1}.`;
  mensaje += `${emoji} ${h}\n`;
});
mensaje += `\nRespondé escribiendo el número del horario que prefieras.\n(Ejemplo: 2)`;

return [{
  json: {
    hayDisponibilidad: true,
    mensaje,
    numero: CallerID,
    instancia: Instance,
    horariosDisponibles: disponibles
  }
}];

const input = $('When Executed by Another Workflow').first().json.Message;
const CallerID = $('When Executed by Another Workflow').first().json.CallerID;
const Instance = $('When Executed by Another Workflow').first().json.Instance;

const opcion = parseInt(input, 10);
const horariosRaw = $('get_HorariosDisponibles').first().json.HorariosDisponibles;

let horariosDisponibles;
if (typeof horariosRaw === 'string') {
  horariosDisponibles = JSON.parse(horariosRaw);
} else if (Array.isArray(horariosRaw)) {
  horariosDisponibles = horariosRaw;
} else {
  horariosDisponibles = [];
}

if (isNaN(opcion) || opcion < 1 || opcion > horariosDisponibles.length) {
  return [{ json: { valido: false, mensaje: '❌ Opción inválida. Respondé con el número del horario.', numero: CallerID, instancia: Instance } }];
}

const horaElegida = horariosDisponibles[opcion - 1];
const fechaRaw = $('Get_date').first().json.fecha_selected;

const fechaDate = new Date(fechaRaw);
const [hh, mm] = horaElegida.split(':').map(Number);
fechaDate.setUTCHours(hh, mm, 0, 0);

const duracion = 30;
const finDate = new Date(fechaDate);
finDate.setMinutes(finDate.getMinutes() + duracion);

const doctorName = $('Get_DoctorName_Hora').first().json.doctorName;
const patientName = $('get_name').first().json.name;

const dia = String(fechaDate.getUTCDate()).padStart(2, '0');
const mes = String(fechaDate.getUTCMonth() + 1).padStart(2, '0');
const anio = fechaDate.getUTCFullYear();
const fechaTexto = `${dia}/${mes}/${anio}`;

const mensaje = `📅 *Confirmación de reagendamiento*\n\n👨‍⚕️ Doctor: ${doctorName}\n👤 Paciente: ${patientName}\n📆 Fecha: ${fechaTexto}\n⏰ Hora: ${horaElegida}\n⌛ Duración: ${duracion} minutos\n\n¿Los datos son correctos?\nRespondé *SI* para confirmar o *NO* para cancelar.`;

return [{
  json: {
    valido: true,
    fecha_hora_inicio: fechaDate.toISOString(),
    fecha_hora_fin: finDate.toISOString(),
    hora_elegida: horaElegida,
    mensaje,
    numero: CallerID,
    instancia: Instance
  }
}];

const dateID = $('Get_DateId').first().json.DateID;
const fechaHoraInicio = $('Get_date_inicio').first().json.dateInicio;
const dt = new Date(fechaHoraInicio);
const new_date = dt.toISOString().substring(0, 10);
const new_time = `${String(dt.getUTCHours()).padStart(2,'0')}:${String(dt.getUTCMinutes()).padStart(2,'0')}`;
const empresaId = $('When Executed by Another Workflow').first().json.empresa_id;
const backendUrl = $('When Executed by Another Workflow').first().json.backend_url;

return [{ json: { dateID, new_date, new_time, empresaId, backendUrl } }];
